    void startWatchdog(){if(watchdogTick!=null)return;watchdogTick=()->{try{getSharedPreferences("p",0).edit().putLong("childServerLastAlive",System.currentTimeMillis()).apply();ChildServerWatchdogReceiver.schedule(this,"watchdog_tick");}catch(Exception ignored){}watchdogHandler.postDelayed(watchdogTick,5L*60L*1000L);};watchdogTick.run();}
    void acquireLocks(){try{WifiManager wm=(WifiManager)getApplicationContext().getSystemService(WIFI_SERVICE);wifiLock=wm.createWifiLock(WifiManager.WIFI_MODE_FULL_HIGH_PERF,"Parental-LinkWifiLock");wifiLock.setReferenceCounted(false);wifiLock.acquire();}catch(Exception e){broadcast("Wi-Fi lock unavailable: "+e.getMessage());}try{PowerManager pm=(PowerManager)getSystemService(POWER_SERVICE);wakeLock=pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK,"Parental-Link:ChildServer");wakeLock.setReferenceCounted(false);wakeLock.acquire();}catch(Exception e){broadcast("Wake lock unavailable: "+e.getMessage());}}
