    void handleSocket(Socket s){String ip="";try{ip=s.getInetAddress().getHostAddress();Long until=blockedIps.get(ip);if(until!=null&&until>System.currentTimeMillis()){s.close();return;}BufferedReader r=new BufferedReader(new InputStreamReader(s.getInputStream()));String line=r.readLine();PrintWriter w=new PrintWriter(s.getOutputStream(),true);if(line!=null&&line.startsWith("PAIR|")){w.println(handlePair(line,ip));s.close();return;}String json;try{json=decrypt(line);}catch(Exception bad){blockedIps.put(ip,System.currentTimeMillis()+60000);broadcast("Bad handshake from "+ip+". Blocked for 60 seconds.");s.close();return;}String resp=handle(new JSONObject(json));w.println(encrypt(resp));s.close();}catch(Exception e){try{s.close();}catch(Exception ignored){}broadcast("Command error: "+e.getMessage());}}

    void startDiscovery(){if(discoveryThread!=null&&discoveryThread.isAlive())return;discoveryThread=new Thread(()->{DatagramSocket listen=null;long lastSent=0;try{listen=new DatagramSocket(null);listen.setReuseAddress(true);listen.bind(new InetSocketAddress(AppConfig.DISCOVERY_PORT));listen.setSoTimeout(2000);}catch(Exception e){broadcast("Discovery listener unavailable: "+e.getMessage());}int[] burst={0,5,15};for(int delay:burst){if(!running)return;try{Thread.sleep(delay*1000L);}catch(Exception ignored){}sendDiscovery();lastSent=System.currentTimeMillis();}byte[] buf=new byte[512];while(running){try{if(listen!=null){DatagramPacket req=new DatagramPacket(buf,buf.length);listen.receive(req);String msg=new String(req.getData(),0,req.getLength(),StandardCharsets.UTF_8);String[] parts=msg.split("\\|");if((parts.length>=2&&parts[0].equals("FLITE_FIND")&&parts[1].equals(pairingId()))||(parts.length>=1&&parts[0].equals("FLITE_PAIR_FIND")))sendDiscovery();}}catch(SocketTimeoutException ignored){}catch(Exception e){if(running)broadcast("Discovery request read failed: "+e.getMessage());}long now=System.currentTimeMillis();if(now-lastSent>30000L){sendDiscovery();lastSent=now;}}try{if(listen!=null)listen.close();}catch(Exception ignored){}},"Parental-LinkDiscovery");discoveryThread.start();}
