    String quickChatSummary(String value){String mode="full",iconKey="chat",text="Message from parent";String[] parts=value==null?new String[0]:value.split("\\|",5);if(parts.length>=3&&(parts[0].equals("banner")||parts[0].equals("full"))){mode=parts[0];iconKey=parts[1].trim().length()>0?parts[1].trim():iconKey;text=parts[2].trim().length()>0?parts[2].trim():text;}else{String[] legacy=value==null?new String[0]:value.split("\\|",2);iconKey=legacy.length>0?legacy[0].trim():iconKey;text=legacy.length>1?legacy[1].trim():text;}return ChatIcons.titlePrefix(iconKey)+": "+text+" ("+(mode.equals("banner")?"banner":"full screen")+")";}

    String childChatStatus(){SharedPreferences p=getSharedPreferences("p",0);String reply=p.getString("lastChildChatReply","");String sent=p.getString("lastChildChatSent","");String parent=p.getString("lastParentChat","");String quick=p.getString("lastParentQuickMessage","");String quickAction=p.getString("lastChildQuickAction","");String seen=p.getString("lastParentChatSeen","");String history=com.enigma.familylinklite.storage.ChatStore.lastLines(this,10);if(reply.length()==0&&sent.length()==0&&parent.length()==0&&quick.length()==0&&quickAction.length()==0&&history.startsWith("No chat"))return "No message activity yet.";StringBuilder sb=new StringBuilder();if(quick.length()>0)sb.append("Last chat message: ").append(quick);if(quickAction.length()>0){if(sb.length()>0)sb.append("\n");sb.append("Child action: ").append(quickAction);}if(parent.length()>0){if(sb.length()>0)sb.append("\n");sb.append("Last parent message: ").append(parent);}if(seen.length()>0){if(sb.length()>0)sb.append("\n");sb.append("Parent message: ").append(seen);}if(reply.length()>0){if(sb.length()>0)sb.append("\n");sb.append("Last child reply: ").append(reply);}if(sent.length()>0){if(sb.length()>0)sb.append("\n");sb.append("Last child chat: ").append(sent);}if(history.length()>0&&!history.startsWith("No chat")){if(sb.length()>0)sb.append("\n\n");sb.append("Recent messages:\n").append(history);}return sb.toString();}
