    boolean hasOverlayPermission(){try{if(Build.VERSION.SDK_INT<23)return true;if(android.provider.Settings.canDrawOverlays(this))return true;AppOpsManager a=(AppOpsManager)getSystemService(APP_OPS_SERVICE);if(a!=null){int mode=a.checkOpNoThrow(AppOpsManager.OPSTR_SYSTEM_ALERT_WINDOW,android.os.Process.myUid(),getPackageName());return mode==AppOpsManager.MODE_ALLOWED;}}catch(Exception ignored){}return false;}
