    String permissionStatus(){boolean admin=false,usage=false,access=false,notif=false,camera=false,microphone=false,overlay=false,dndPolicy=false,battery=false;try{DevicePolicyManager dpm=(DevicePolicyManager)getSystemService(DEVICE_POLICY_SERVICE);admin=dpm!=null&&dpm.isAdminActive(new ComponentName(this,AdminReceiver.class));}catch(Exception ignored){}try{AppOpsManager a=(AppOpsManager)getSystemService(APP_OPS_SERVICE);usage=a.checkOpNoThrow(AppOpsManager.OPSTR_GET_USAGE_STATS,android.os.Process.myUid(),getPackageName())==AppOpsManager.MODE_ALLOWED;}catch(Exception ignored){}try{String enabled=android.provider.Settings.Secure.getString(getContentResolver(),android.provider.Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES);access=enabled!=null&&enabled.toLowerCase(java.util.Locale.US).contains(getPackageName().toLowerCase(java.util.Locale.US));}catch(Exception ignored){}notif=hasNotificationPermission();camera=hasCameraPermission();microphone=hasMicrophonePermission();overlay=hasOverlayPermission();try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);dndPolicy=nm!=null&&nm.isNotificationPolicyAccessGranted();}catch(Exception ignored){}battery=hasBatteryUnrestricted();return "admin="+admin+",usage="+usage+",accessibility="+access+",notifications="+notif+",camera="+camera+",microphone="+microphone+",overlay="+overlay+",dndPolicy="+dndPolicy+",battery="+battery;}
    String dndStatus(){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);int filter=nm.getCurrentInterruptionFilter();boolean access=nm.isNotificationPolicyAccessGranted();String label="unknown";if(filter==NotificationManager.INTERRUPTION_FILTER_ALL)label="OFF";else if(filter==NotificationManager.INTERRUPTION_FILTER_PRIORITY||filter==NotificationManager.INTERRUPTION_FILTER_ALARMS||filter==NotificationManager.INTERRUPTION_FILTER_NONE)label="ON";return label+" / policy access "+(access?"yes":"no");}catch(Exception e){return "unknown";}}
    String allowPingThroughDnd(){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);if(nm==null)return "DND service unavailable";if(!nm.isNotificationPolicyAccessGranted())return "DND policy access missing";previousDndFilter=nm.getCurrentInterruptionFilter();nm.setInterruptionFilter(NotificationManager.INTERRUPTION_FILTER_ALL);getSharedPreferences("rules",0).edit().putInt("previous_dnd_filter",previousDndFilter).apply();return "DND temporarily opened for ping";}catch(Exception e){return "DND change failed: "+e.getMessage();}}
    String restoreDndFilter(){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);if(nm==null)return "DND service unavailable";int saved=getSharedPreferences("rules",0).getInt("previous_dnd_filter",previousDndFilter);if(nm.isNotificationPolicyAccessGranted()&&saved>0){nm.setInterruptionFilter(saved);getSharedPreferences("rules",0).edit().remove("previous_dnd_filter").apply();previousDndFilter=-1;return "DND restored";}return "DND restore skipped";}catch(Exception e){return "DND restore failed: "+e.getMessage();}}
    void requestParentUnlock(String reason){
        SharedPreferences p=getSharedPreferences("rules",0);
        long now=System.currentTimeMillis();
        long snoozeUntil=p.getLong("ask_parent_snooze_until",0);
        if(snoozeUntil>now){
            long mins=Math.max(1,(snoozeUntil-now+59999)/60000);
            broadcast("Ask Parent snoozed for "+mins+" min");
            showCommandNotification("Ask Parent paused", "Ask again in "+mins+" min.");
            return;
        }
        long last=p.getLong("last_unlock_request",0);
        String cleanReason=(reason==null||reason.trim().length()==0)?"limitation":reason.trim();
        if(now-last<5*60*1000L){
            broadcast("Unlock request already sent recently");
            showCommandNotification("Unlock request pending", "Your parent was already notified. Try again later.");
            return;
        }
        p.edit().putLong("last_unlock_request",now).putString("last_unlock_reason",cleanReason).apply();
        showCommandNotification("Unlock requested", "Child asks to unlock: "+cleanReason);
        broadcast("Child requested unlock: "+cleanReason);
    }

    void setMediaVol(int percent){AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int max=a.getStreamMaxVolume(AudioManager.STREAM_MUSIC);int v=Math.max(0,Math.min(max,Math.round(max*percent/100f)));a.setStreamVolume(AudioManager.STREAM_MUSIC,v,0);}
    void startAlarm(){alarm=true;getSharedPreferences("rules",0).edit().putBoolean("ping_active",true).apply();allowPingThroughDnd();try{AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int maxMusic=a.getStreamMaxVolume(AudioManager.STREAM_MUSIC);int maxAlarm=a.getStreamMaxVolume(AudioManager.STREAM_ALARM);int targetMusic=Math.max(1,Math.round(maxMusic*0.85f));int targetAlarm=Math.max(1,Math.round(maxAlarm*0.85f));a.adjustStreamVolume(AudioManager.STREAM_MUSIC,AudioManager.ADJUST_UNMUTE,0);a.adjustStreamVolume(AudioManager.STREAM_ALARM,AudioManager.ADJUST_UNMUTE,0);a.setStreamVolume(AudioManager.STREAM_MUSIC,targetMusic,0);a.setStreamVolume(AudioManager.STREAM_ALARM,targetAlarm,0);}catch(Exception ignored){}if(tone==null)tone=new ToneGenerator(AudioManager.STREAM_ALARM,80);showCommandNotification("Parent is pinging", "The tablet is playing a softer attention chime. Stop it from the tablet or parent phone.");try{Intent pi=new Intent(this, com.enigma.familylinklite.PingActivity.class);pi.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK|Intent.FLAG_ACTIVITY_CLEAR_TOP);startActivity(pi);}catch(Exception ignored){}new Thread(()->{while(alarm){try{tone.startTone(ToneGenerator.TONE_PROP_PROMPT,450);Thread.sleep(2600);}catch(Exception ignored){}}},"Parental-LinkPingChime").start();}
