    String currentApp(){String pkg=currentPackage();if(pkg.length()==0||isExcludedUsagePackage(pkg))return "Unavailable";try{PackageManager pm=getPackageManager();ApplicationInfo ai=pm.getApplicationInfo(pkg,0);String category=appCategory(ai);return pm.getApplicationLabel(ai).toString()+" ("+pkg+")"+(category.length()>0?" ["+category+"]":"");}catch(Exception e){return pkg;}}
